const allItems = $input.all();

const result = {
  turnos: [],
  nuevos: [],
  pendientes: [],
  recetas: []
};

for (const item of allItems) {
  const fuente = item.json.fuente;
  if (fuente === 'turnos') result.turnos.push(item.json);
  else if (fuente === 'nuevos') result.nuevos.push(item.json);
  else if (fuente === 'mensajes') result.pendientes.push(item.json);
  else if (fuente === 'recetas') result.recetas.push(item.json);
}

return [{
  json: {
    turnos: result.turnos,
    nuevos: result.nuevos,
    pendientes: result.pendientes,
    recetas: result.recetas,
    totalTurnos: result.turnos.length,
    totalNuevos: result.nuevos.length,
    totalPendientes: result.pendientes.length,
    totalRecetas: result.recetas.length
  }
}];

